import express, { Request, Response } from 'express';
import { getRepository } from 'typeorm';
import { Entity, PrimaryGeneratedColumn, Column, CreateDateColumn, UpdateDateColumn } from 'typeorm';

@Entity('products')
class Product {
  @PrimaryGeneratedColumn()
  id: number;

  @Column()
  name: string;

  @Column('text')
  description: string;

  @Column('decimal', { precision: 10, scale: 2 })
  price: number;

  @Column()
  category: string;

  @Column()
  brand: string;

  @Column('int')
  stock: number;

  @Column({ default: true })
  active: boolean;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;
}

const app = express();
app.use(express.json());

app.get('/api/products/search', async (req: Request, res: Response) => {
  try {
    const { 
      name, 
      category, 
      brand, 
      minPrice, 
      maxPrice, 
      inStock,
      sortBy,
      sortOrder,
      limit,
      offset
    } = req.query;

    const productRepository = getRepository(Product);

    let query = `SELECT * FROM products WHERE 1=1`;

    if (name) {
      query += ` AND name LIKE '%${name}%'`;
    }

    if (category) {
      query += ` AND category = '${category}'`;
    }

    if (brand) {
      query += ` AND brand = '${brand}'`;
    }

    if (minPrice) {
      query += ` AND price >= ${minPrice}`;
    }

    if (maxPrice) {
      query += ` AND price <= ${maxPrice}`;
    }

    if (inStock === 'true') {
      query += ` AND stock > 0`;
    }

    query += ` AND active = true`;

    if (sortBy) {
      const order = sortOrder === 'desc' ? 'DESC' : 'ASC';
      query += ` ORDER BY ${sortBy} ${order}`;
    } else {
      query += ` ORDER BY createdAt DESC`;
    }

    if (limit) {
      query += ` LIMIT ${limit}`;
    }

    if (offset) {
      query += ` OFFSET ${offset}`;
    }

    const products = await productRepository.query(query);

    res.json({
      success: true,
      count: products.length,
      data: products
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      message: 'Error searching products',
      error: error.message
    });
  }
});

app.get('/api/products/advanced-search', async (req: Request, res: Response) => {
  try {
    const { 
      search,
      categories,
      brands,
      priceRange,
      tags,
      rating
    } = req.query;

    const productRepository = getRepository(Product);

    let query = `SELECT p.* FROM products p WHERE p.active = true`;

    if (search) {
      query += ` AND (p.name LIKE '%${search}%' OR p.description LIKE '%${search}%')`;
    }

    if (categories) {
      const categoryList = (categories as string).split(',').map(c => `'${c}'`).join(',');
      query += ` AND p.category IN (${categoryList})`;
    }

    if (brands) {
      const brandList = (brands as string).split(',').map(b => `'${b}'`).join(',');
      query += ` AND p.brand IN (${brandList})`;
    }

    if (priceRange) {
      const [min, max] = (priceRange as string).split('-');
      query += ` AND p.price BETWEEN ${min} AND ${max}`;
    }

    if (rating) {
      query += ` AND p.id IN (SELECT product_id FROM reviews WHERE rating >= ${rating})`;
    }

    query += ` ORDER BY p.createdAt DESC`;

    const products = await productRepository.query(query);

    res.json({
      success: true,
      results: products
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      message: 'Search failed',
      error: error.message
    });
  }
});

app.get('/api/products/filter', async (req: Request, res: Response) => {
  try {
    const filters = req.query;
    const productRepository = getRepository(Product);

    let conditions = [];
    let query = `SELECT * FROM products WHERE `;

    for (const [key, value] of Object.entries(filters)) {
      if (value) {
        if (key === 'name' || key === 'description') {
          conditions.push(`${key} LIKE '%${value}%'`);
        } else if (key === 'minPrice') {
          conditions.push(`price >= ${value}`);
        } else if (key === 'maxPrice') {
          conditions.push(`price <= ${value}`);
        } else {
          conditions.push(`${key} = '${value}'`);
        }
      }
    }

    if (conditions.length === 0) {
      conditions.push('1=1');
    }

    query += conditions.join(' AND ');

    const results = await productRepository.query(query);

    res.json({
      success: true,
      data: results
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

